"use client";

import { BackButton } from "@/shared/ui/back-button-new/back-button";
import { CreateTicketForm } from "@/widgets/create-ticket-form";
import { useRouter } from "next/navigation";

export default function CreateTicketPage() {
  const router = useRouter();

  function handleSuccess(_ticketId: string) {
    router.push("/support");
  }

  return (
    <div className="mx-auto max-w-[600px]">
      <div className="mb-8">
        <BackButton onClick={() => router.back()} label="Back" />
      </div>

      <h1 className="font-light font-new-serif text-[#44403C] text-[2rem] leading-[120%]">
        Raise a Support Ticket
      </h1>
      <p className="mt-2 font-new-sans text-[#A8A29E] text-sm">
        Share enough details to get your issue resolved. Our team will evaluate
        your request and will address it soon.
      </p>

      <div className="my-6 border-[#D6D3D1] border-t" />

      <CreateTicketForm onSuccess={handleSuccess} />
    </div>
  );
}

