"use client";

import { APP_ROUTES } from "@/shared/config/app-routes";
import { BackButton } from "@/shared/ui/back-button";
import { AlternativeContact } from "@/widgets/alternative-contact";
import { TicketDetail } from "@/widgets/ticket-detail";
import { useParams, useRouter } from "next/navigation";

export default function TicketDetailPage() {
  const router = useRouter();
  const params = useParams();
  const ticketId = params.id as string;

  function handleCancel() {
    router.push(APP_ROUTES.TICKETS.ROOT);
  }

  return (
    <div className="container mx-auto max-w-4xl px-3 py-6 sm:px-4 sm:py-8">
      <BackButton label="Back to Tickets" onClick={() => router.back()} />

      <div className="mt-4 sm:mt-6">
        <TicketDetail
          ticketId={ticketId}
          onCancel={handleCancel}
          showCancelButton
        />
      </div>

      <AlternativeContact className="mt-6 sm:mt-8" />
    </div>
  );
}

