1	"use client";
2	
3	import {
4	  useActiveBuybacks,
5	  useBuybackRequests,
6	} from "@/shared/api/query-hooks/use-buyback-requests";
7	import { useFileUpload } from "@/shared/api/query-hooks/use-file-upload";
8	import { useCreateTicket } from "@/shared/api/query-hooks/use-tickets";
9	import type { MimeType } from "@/shared/constants/mime-types";
10	import { S3_FOLDERS } from "@/shared/constants/mime-types";
11	import { TICKET_CATEGORY_LABELS } from "@/shared/constants/ticket";
12	import { generateItemTitle, getSecondaryDisplayInfo } from "@/shared/lib/items";
13	import { sanitizeFileName } from "@/shared/lib/utils/file-name-utils";
14	import { NotificationMedia, TicketCategory } from "@/shared/types/ticket.types";
15	import { Checkbox } from "@/shared/ui/checkbox";
16	import { toast } from "@/shared/ui/notification";
17	import {
18	  Select,
19	  SelectContent,
20	  SelectItem,
21	  SelectTrigger,
22	  SelectValue,
23	} from "@/shared/ui/select";
24	import { zodResolver } from "@hookform/resolvers/zod";
25	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
26	import { type Resolver, useForm } from "react-hook-form";
27	import { z } from "zod";
28	import type { CreateTicketFormProps } from "../model/types";
29	
30	const MAX_FILES = 5;
31	const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5 MB
32	
33	const createTicketSchema = z.object({
34	  description: z
35	    .string()
36	    .min(1, "Description is required")
37	    .min(5, "Description must be at least 5 characters")
38	    .max(2000, "Description must be less than 2000 characters"),
39	  category: z.nativeEnum(TicketCategory, {
40	    errorMap: () => ({ message: "Please select a category" }),
41	  }),
42	  referenceId: z.string().optional(),
43	  attachedFileIds: z
44	    .array(z.string())
45	    .max(MAX_FILES, `Maximum ${MAX_FILES} files allowed`),
46	  preferredContactMethods: z
47	    .array(z.nativeEnum(NotificationMedia))
48	    .min(1, "Select at least one contact method"),
49	});
50	
51	type CreateTicketFormData = z.infer<typeof createTicketSchema>;
52	
53	export function CreateTicketForm({
54	  onSuccess,
55	  onCancel,
56	}: CreateTicketFormProps) {
57	  const [uploadedFiles, setUploadedFiles] = useState<
58	    Array<{ id: string; name: string }>
59	  >([]);
60	  const [isUploadingFiles, setIsUploadingFiles] = useState(false);
61	  const [isDragOver, setIsDragOver] = useState(false);
62	  const [referenceSearch, setReferenceSearch] = useState("");
63	  const [debouncedSearch, setDebouncedSearch] = useState("");
64	  const [isReferenceSelectOpen, setIsReferenceSelectOpen] = useState(false);
65	  const fileInputRef = useRef<HTMLInputElement>(null);
66	
67	  const createTicketMutation = useCreateTicket();
68	  const fileUploadMutation = useFileUpload();
69	
70	  const {
71	    register,
72	    handleSubmit,
73	    watch,
74	    setValue,
75	    formState: { errors },
76	  } = useForm<CreateTicketFormData>({
77	    resolver: zodResolver(createTicketSchema) as Resolver<CreateTicketFormData>,
78	    defaultValues: {
79	      attachedFileIds: [],
80	      preferredContactMethods: [NotificationMedia.Email],
81	    },
82	  });
83	
84	  const selectedCategory = watch("category");
85	  const selectedContactMethods = watch("preferredContactMethods");
86	  const selectedReferenceId = watch("referenceId");
87	
88	  useEffect(() => {
89	    const timer = setTimeout(() => {
90	      setDebouncedSearch(referenceSearch);
91	    }, 300);
92	
93	    return () => clearTimeout(timer);
94	  }, [referenceSearch]);
95	
96	  const { data: buybacksData, isLoading: isLoadingBuybacks } =
97	    useActiveBuybacks({ search: debouncedSearch || undefined });
98	
99	  const { data: buybackRequestsData, isLoading: isLoadingBuybackRequests } =
100	    useBuybackRequests({ search: debouncedSearch || undefined });
101	
102	  function handleContactMethodToggle(method: NotificationMedia) {
103	    const current = selectedContactMethods || [];
104	
105	    if (current.includes(method)) {
106	      const newMethods = current.filter((m) => m !== method);
107	
108	      if (newMethods.length === 0) {
109	        toast.error("At least one contact method is required");
110	
111	        return;
112	      }
113	
114	      setValue("preferredContactMethods", newMethods, { shouldValidate: true });
115	    } else {
116	      setValue("preferredContactMethods", [...current, method], {
117	        shouldValidate: true,
118	      });
119	    }
120	  }
121	
122	  async function processFiles(files: File[]) {
123	    const remainingSlots = MAX_FILES - uploadedFiles.length;
124	
125	    if (remainingSlots <= 0) {
126	      toast.error(`Maximum ${MAX_FILES} files allowed`);
127	
128	      return;
129	    }
130	
131	    const filesToProcess = files.slice(0, remainingSlots);
132	    const oversized = files.filter((f) => f.size > MAX_FILE_SIZE);
133	
134	    if (oversized.length > 0) {
135	      toast.error(`${oversized.length} file(s) exceed the 5 MB limit`);
136	    }
137	
138	    const validFiles = filesToProcess.filter((f) => f.size <= MAX_FILE_SIZE);
139	
140	    if (validFiles.length === 0) return;
141	
142	    setIsUploadingFiles(true);
143	
144	    const uploadResults: Array<{ id: string; name: string }> = [];
145	
146	    for (const file of validFiles) {
147	      try {
148	        const fileNameInfo = sanitizeFileName(file.name);
149	
150	        const result = await fileUploadMutation.mutateAsync({
151	          file,
152	          mime: file.type as MimeType,
153	          fileName: fileNameInfo.sanitized,
154	          folder: S3_FOLDERS.FILES,
155	        });
156	
157	        uploadResults.push({ id: result.fileId, name: fileNameInfo.original });
158	      } catch {
159	        toast.error(`Failed to upload ${file.name}`);
160	      }
161	    }
162	
163	    const newUploadedFiles = [...uploadedFiles, ...uploadResults];
164	
165	    setUploadedFiles(newUploadedFiles);
166	    setValue(
167	      "attachedFileIds",
168	      newUploadedFiles.map((f) => f.id),
169	      { shouldValidate: true },
170	    );
171	
172	    setIsUploadingFiles(false);
173	  }
174	
175	  function handleRemoveFile(fileId: string) {
176	    const newUploadedFiles = uploadedFiles.filter((f) => f.id !== fileId);
177	
178	    setUploadedFiles(newUploadedFiles);
179	    setValue(
180	      "attachedFileIds",
181	      newUploadedFiles.map((f) => f.id),
182	      { shouldValidate: true },
183	    );
184	  }
185	
186	  const handleDragOver = useCallback((e: React.DragEvent) => {
187	    e.preventDefault();
188	    setIsDragOver(true);
189	  }, []);
190	
191	  const handleDragLeave = useCallback((e: React.DragEvent) => {
192	    e.preventDefault();
193	    setIsDragOver(false);
194	  }, []);
195	
196	  function handleDrop(e: React.DragEvent) {
197	    e.preventDefault();
198	    setIsDragOver(false);
199	
200	    const files = Array.from(e.dataTransfer.files);
201	    const accepted = files.filter((f) =>
202	      ["application/pdf", "image/jpeg", "image/png"].includes(f.type),
203	    );
204	
205	    if (accepted.length < files.length) {
206	      toast.error("Only .PDF, .JPG, .PNG files are supported");
207	    }
208	
209	    if (accepted.length > 0) {
210	      processFiles(accepted);
211	    }
212	  }
213	
214	  async function onSubmit(data: CreateTicketFormData) {
215	    const subject = data.description.slice(0, 100).trim() || "Support Request";
216	
217	    createTicketMutation.mutate(
218	      {
219	        subject,
220	        description: data.description,
221	        category: data.category,
222	        referenceId: data.referenceId,
223	        attachedFileIds: data.attachedFileIds,
224	        preferredContactMethods: data.preferredContactMethods,
225	      },
226	      {
227	        onSuccess: (ticket) => {
228	          toast.success("Ticket submitted successfully");
229	          onSuccess?.(ticket.id);
230	        },
231	        onError: () => {
232	          toast.error("Failed to create ticket");
233	        },
234	      },
235	    );
236	  }
237	
238	  const referenceOptions = useMemo(() => {
239	    if (selectedCategory === TicketCategory.ActiveBuyback) {
240	      return (
241	        buybacksData?.data.map((b) => {
242	          const asset = b.asset;
243	          const itemTitle = generateItemTitle(
244	            asset.category.name,
245	            asset.categoryFields,
246	          );
247	          const secondaryInfo = getSecondaryDisplayInfo(
248	            asset.category.name,
249	            asset.categoryFields,
250	          );
251	
252	          return {
253	            value: b.id,
254	            label: `Buyback #${b.id.slice(0, 8)}`,
255	            details: `${itemTitle} · ${secondaryInfo}`,
256	          };
257	        }) || []
258	      );
259	    }
260	
261	    if (selectedCategory === TicketCategory.BuybackRequest) {
262	      return (
263	        buybackRequestsData?.data.map((br) => {
264	          const asset = br.buyback.asset;
265	          const itemTitle = generateItemTitle(
266	            asset.category.name,
267	            asset.categoryFields,
268	          );
269	          const secondaryInfo = getSecondaryDisplayInfo(
270	            asset.category.name,
271	            asset.categoryFields,
272	          );
273	
274	          return {
275	            value: br.id,
276	            label: `Request #${br.id.slice(0, 8)}`,
277	            details: `${itemTitle} · ${secondaryInfo}`,
278	          };
279	        }) || []
280	      );
281	    }
282	
283	    return [];
284	  }, [selectedCategory, buybacksData, buybackRequestsData]);
285	
286	  const isLoadingReference =
287	    selectedCategory === TicketCategory.ActiveBuyback
288	      ? isLoadingBuybacks
289	      : isLoadingBuybackRequests;
290	
291	  const showReferenceSelect =
292	    selectedCategory === TicketCategory.ActiveBuyback ||
293	    selectedCategory === TicketCategory.BuybackRequest;
294	
295	  const descriptionValue = watch("description") || "";
296	  const isSubmitting = createTicketMutation.isPending || isUploadingFiles;
297	
298	  return (
299	    <form className="flex flex-col gap-6" onSubmit={handleSubmit(onSubmit)}>
300	      {/* Category */}
301	      <div className="flex flex-col gap-1.5">
302	        <label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
303	          Category
304	        </label>
305	        <Select
306	          onValueChange={(value) =>
307	            setValue("category", value as TicketCategory, {
308	              shouldValidate: true,
309	            })
310	          }
311	        >
312	          <SelectTrigger
313	            className={`h-12 rounded-[4px] border font-new-sans text-[#44403C] text-sm ${
314	              errors.category ? "border-red-400" : "border-[#A8A29E]"
315	            }`}
316	          >
317	            <SelectValue placeholder="Select an option" />
318	          </SelectTrigger>
319	          <SelectContent>
320	            {Object.values(TicketCategory).map((category) => (
321	              <SelectItem key={category} value={category}>
322	                {TICKET_CATEGORY_LABELS[category]}
323	              </SelectItem>
324	            ))}
325	          </SelectContent>
326	        </Select>
327	        {errors.category && (
328	          <p className="font-new-sans text-red-500 text-xs">
329	            {errors.category.message}
330	          </p>
331	        )}
332	      </div>
333	
334	      {/* Related order */}
335	      {showReferenceSelect && (
336	        <div className="flex flex-col gap-1.5">
337	          <div className="flex items-center gap-2">
338	            <label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
339	              Related order
340	            </label>
341	            <svg
342	              aria-hidden="true"
343	              className="text-[#A8A29E]"
344	              fill="none"
345	              height="14"
346	              viewBox="0 0 16 16"
347	              width="14"
348	            >
349	              <circle
350	                cx="8"
351	                cy="8"
