"use client";

import {
  useCancelTicket,
  useTicket,
} from "@/shared/api/query-hooks/use-tickets";
import {
  TICKET_CATEGORY_LABELS,
  TICKET_STATUS_LABELS,
} from "@/shared/constants/ticket";
import { TicketStatus } from "@/shared/types/ticket.types";
import { Badge } from "@/shared/ui/badge";
import { Button } from "@/shared/ui/button";
import { toast } from "@/shared/ui/notification";
import { Separator } from "@/shared/ui/separator";
import { format } from "date-fns";
import type { TicketDetailProps } from "../model/types";

function getStatusBadgeVariant(status: TicketStatus) {
  if (status === TicketStatus.Open) return "primary";
  if (status === TicketStatus.Resolved) return "success";
  if (status === TicketStatus.Rejected) return "error";

  return "default";
}

export function TicketDetail({
  ticketId,
  onCancel,
  showCancelButton = true,
}: TicketDetailProps) {
  const { data: ticket, isLoading } = useTicket(ticketId);
  const cancelTicketMutation = useCancelTicket();

  function handleCancel() {
    cancelTicketMutation.mutate(ticketId, {
      onSuccess: () => {
        toast.success("Ticket cancelled successfully");
        onCancel?.(ticketId);
      },
      onError: () => {
        toast.error("Failed to cancel ticket");
      },
    });
  }

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <p className="text-muted-foreground">Loading ticket details...</p>
      </div>
    );
  }

  if (!ticket) {
    return (
      <div className="flex items-center justify-center py-12">
        <p className="text-destructive">Ticket not found</p>
      </div>
    );
  }

  const canCancel = ticket.status === TicketStatus.Open && showCancelButton;

  return (
    <div className="flex flex-col gap-6">
      <div className="flex items-start justify-between">
        <div className="flex flex-col gap-2">
          <h2 className="font-bold font-serif text-2xl text-foreground">
            {ticket.subject}
          </h2>
          <div className="flex items-center gap-3">
            <Badge variant={getStatusBadgeVariant(ticket.status)}>
              {TICKET_STATUS_LABELS[ticket.status]}
            </Badge>
            <span className="text-muted-foreground text-sm">
              {TICKET_CATEGORY_LABELS[ticket.category]}
            </span>
          </div>
        </div>

        {canCancel && (
          <Button
            variant="destructive"
            onClick={handleCancel}
            loading={cancelTicketMutation.isPending}
          >
            Cancel Ticket
          </Button>
        )}
      </div>

      <Separator />

      <div className="grid grid-cols-2 gap-6">
        <div className="flex flex-col gap-1">
          <span className="text-muted-foreground text-sm">Created</span>
          <span className="font-serif text-base text-foreground">
            {format(new Date(ticket.createdAt), "MMM dd, yyyy HH:mm")}
          </span>
        </div>

        {ticket.closedAt && (
          <div className="flex flex-col gap-1">
            <span className="text-muted-foreground text-sm">Closed</span>
            <span className="font-serif text-base text-foreground">
              {format(new Date(ticket.closedAt), "MMM dd, yyyy HH:mm")}
            </span>
          </div>
        )}

        {ticket.referenceId && (
          <div className="flex flex-col gap-1">
            <span className="text-muted-foreground text-sm">Reference ID</span>
            <span className="font-serif text-base text-foreground">
              {ticket.referenceId}
            </span>
          </div>
        )}

        <div className="flex flex-col gap-1">
          <span className="text-muted-foreground text-sm">
            Preferred Contact Methods
          </span>
          <div className="flex gap-2">
            {ticket.preferredContactMethods.map((method) => (
              <Badge key={method} variant="outline">
                {method}
              </Badge>
            ))}
          </div>
        </div>
      </div>

      <Separator />

      <div className="flex flex-col gap-2">
        <h3 className="font-bold font-serif text-foreground text-lg">
          Description
        </h3>
        <p className="whitespace-pre-wrap font-serif text-base text-foreground">
          {ticket.description}
        </p>
      </div>

      {ticket.attachedFiles.length > 0 && (
        <>
          <Separator />
          <div className="flex flex-col gap-2">
            <h3 className="font-bold font-serif text-foreground text-lg">
              Attachments
            </h3>
            <div className="flex flex-col gap-2">
              {ticket.attachedFiles.map((fileId) => (
                <div
                  key={fileId}
                  className="flex items-center gap-2 rounded-lg border border-input p-3"
                >
                  <span className="font-serif text-foreground text-sm">
                    {fileId}
                  </span>
                </div>
              ))}
            </div>
          </div>
        </>
      )}

      {ticket.adminComment && (
        <>
          <Separator />
          <div className="flex flex-col gap-2 rounded-lg bg-secondary/10 p-4">
            <h3 className="font-bold font-serif text-foreground text-lg">
              Admin Response
            </h3>
            <p className="whitespace-pre-wrap font-serif text-base text-foreground">
              {ticket.adminComment}
            </p>
          </div>
        </>
      )}
    </div>
  );
}

