import { ArrowLeftIcon } from "lucide-react";
import Link from "next/link";

interface BackButtonLinkProps {
  href: string;
  label: string;
  onClick?: never;
}

interface BackButtonActionProps {
  href?: never;
  label: string;
  onClick: () => void;
}

type BackButtonProps = BackButtonLinkProps | BackButtonActionProps;

const className =
  "w-fit flex items-center gap-2 rounded-[8px] border border-border px-2 py-2 font-[500] font-new-sans text-xs leading-[130%] hover:opacity-70";

export function BackButton({ href, label, onClick }: BackButtonProps) {
  if (href) {
    return (
      <Link className={className} href={href}>
        <ArrowLeftIcon size={16} />
        {label}
      </Link>
    );
  }

  return (
    <button className={className} onClick={onClick} type="button">
      <ArrowLeftIcon size={16} />
      {label}
    </button>
  );
}

