372	        d="M6 1v10M3 4l3-3 3 3"
373	        stroke={active && dir === "asc" ? "#44403C" : "#D6D3D1"}
374	        strokeLinecap="round"
375	        strokeLinejoin="round"
376	        strokeWidth="1.2"
377	      />
378	      <path
379	        d="M3 8l3 3 3-3"
380	        stroke={active && dir === "desc" ? "#44403C" : "#D6D3D1"}
381	        strokeLinecap="round"
382	        strokeLinejoin="round"
383	        strokeWidth="1.2"
384	      />
385	    </svg>
386	  );
387	}
