389	function TicketListContent({
390	  isLoading,
391	  isAuthenticated,
392	  tickets,
393	  onTicketClick,
394	}: {
395	  isLoading: boolean;
396	  isAuthenticated: boolean;
397	  tickets: TicketListItem[];
398	  onTicketClick: (id: string) => void;
399	}) {
400	  const [sortKey, setSortKey] = useState<SortKey>("date");
401	  const [sortDir, setSortDir] = useState<SortDir>("desc");
402	
403	  function handleSort(key: SortKey) {
404	    if (sortKey === key) {
405	      setSortDir((prev) => (prev === "asc" ? "desc" : "asc"));
406	    } else {
407	      setSortKey(key);
408	      setSortDir("asc");
409	    }
410	  }
411	
412	  if (isLoading) return <TicketSkeleton />;
413	  if (!isAuthenticated) return <GuestEmptyState />;
414	  if (tickets.length === 0) return <AuthEmptyState />;
415	
416	  const sorted = sortTickets(tickets, sortKey, sortDir);
