422	      </div>
423	      <div className="hidden w-full overflow-x-auto sm:block">
424	        <table className="w-full min-w-[700px]">
425	          <thead>
426	            <tr className="border-[#E7E5E4] border-b">
427	              {COLUMNS.map((col) => (
428	                <th
429	                  className="py-3 pr-3 pl-6 text-left first:pl-6 last:pr-4"
430	                  key={col.label}
431	                >
432	                  {col.sortKey ? (
433	                    <button
434	                      className="flex items-center gap-1 font-medium font-new-sans text-[#A8A29E] text-xs transition-colors hover:text-[#44403C]"
435	                      onClick={() => handleSort(col.sortKey as SortKey)}
436	                      type="button"
437	                    >
438	                      {col.label}
439	                      <SortIcon
440	                        active={sortKey === col.sortKey}
