442	                      />
443	                    </button>
444	                  ) : (
445	                    <span className="font-medium font-new-sans text-[#A8A29E] text-xs">
446	                      {col.label}
447	                    </span>
448	                  )}
449	                </th>
450	              ))}
451	            </tr>
