"use client";

import { useCancelTicket, useDeleteTicket, useTicket } from "@/shared/api/query-hooks/use-tickets";
import { ApiKeys } from "@/shared/api/query-keys";
import { useQueryClient } from "@tanstack/react-query";
import {
  TICKET_CATEGORY_LABELS,
  TICKET_STATUS_LABELS,
} from "@/shared/constants/ticket";
import { TicketStatus } from "@/shared/types/ticket.types";
import { toast } from "@/shared/ui/notification";
import { format } from "date-fns";
import Link from "next/link";
import { useParams, useRouter } from "next/navigation";
import { Suspense } from "react";

const STATUS_BADGE: Record<TicketStatus, string> = {
  [TicketStatus.Open]: "bg-[#D1FAE5] text-[#065F46]",
  [TicketStatus.Resolved]: "bg-[#D1FAE5] text-[#065F46]",
  [TicketStatus.Rejected]: "bg-[#FEE2E2] text-[#B91C1C]",
  [TicketStatus.Cancelled]: "bg-[#F3F4F6] text-[#6B7280]",
};

function SupportTicketDetail({ ticketId }: { ticketId: string }) {
  const router = useRouter();
  const queryClient = useQueryClient();
  const { data: ticket, isLoading } = useTicket(ticketId);
  const deleteMutation = useDeleteTicket();
  const cancelMutation = useCancelTicket();

  function navigateToSupport() {
    queryClient.removeQueries({ queryKey: ApiKeys.tickets() });
    router.push("/support");
  }

  function handleDelete() {
    deleteMutation.mutate(ticketId, {
      onSuccess: () => {
        toast.success("Ticket deleted successfully");
        navigateToSupport();
      },
      onError: () => {
        toast.error("Failed to delete ticket");
      },
    });
  }

  function handleArchive() {
    if (ticket?.status !== TicketStatus.Open) {
      navigateToSupport();
      return;
    }
    cancelMutation.mutate(ticketId, {
      onSuccess: () => {
        toast.success("Ticket archived successfully");
        navigateToSupport();
      },
      onError: () => {
        toast.error("Failed to archive ticket");
      },
    });
  }

  if (isLoading) {
    return (
      <div className="flex flex-col gap-4">
        {[1, 2, 3, 4].map((i) => (
          <div key={i} className="h-10 animate-pulse rounded-lg bg-[#EDE9E3]" />
        ))}
      </div>
    );
  }

  if (!ticket) {
    return (
      <p className="font-new-sans text-[#A8A29E] text-sm">Ticket not found.</p>
    );
  }

  const shortId = ticket.id.replace(/-/g, "").slice(0, 5).toUpperCase();

  return (
    <div className="flex flex-col gap-8">
      {/* Title */}
      <h1 className="font-extralight font-new-serif text-4xl text-[#44403C] leading-[120%]">
        Ticket{shortId} Details
      </h1>

      {/* Admin comment */}
      {ticket.adminComment && (
        <div className="flex gap-3 rounded-2xl border border-[#D6D3D1] bg-[#F5F3EF] p-5">
          <svg
            width="18"
            height="18"
            viewBox="0 0 24 24"
            fill="none"
            aria-hidden="true"
            className="mt-0.5 shrink-0"
          >
            <circle cx="12" cy="12" r="10" stroke="#44403C" strokeWidth="1.5" />
            <path
              d="M12 8v4M12 16h.01"
              stroke="#44403C"
              strokeWidth="1.5"
              strokeLinecap="round"
            />
          </svg>
          <div className="flex flex-col gap-1">
            <span className="font-medium font-new-sans text-[#44403C] text-sm">
              LuxFlow comment
            </span>
            <p className="font-new-sans text-[#44403C] text-sm leading-relaxed">
              {ticket.adminComment}
            </p>
          </div>
        </div>
      )}

      {/* Info rows */}
      <div className="flex flex-col">
        <InfoRow label="Status">
          <span
            className={`inline-flex items-center rounded px-2.5 py-0.5 font-medium font-new-sans text-xs ${STATUS_BADGE[ticket.status]}`}
          >
            {TICKET_STATUS_LABELS[ticket.status]}
          </span>
        </InfoRow>

        <InfoRow label="Date">
          <span className="font-medium font-new-sans text-[#44403C] text-sm">
            {format(new Date(ticket.createdAt), "MMM dd, yyyy")}
          </span>
        </InfoRow>

        <InfoRow label="Issue Category">
          <span className="font-medium font-new-sans text-[#44403C] text-sm">
            {TICKET_CATEGORY_LABELS[ticket.category]}
          </span>
        </InfoRow>

        <InfoRow label="Related Order">
          <span className="font-medium font-new-sans text-[#44403C] text-sm">
            {ticket.referenceId ?? "N/A"}
          </span>
        </InfoRow>

        <div className="flex flex-col gap-2 border-[#E7E5E4] border-t py-4">
          <span className="font-new-sans text-[#A8A29E] text-sm">
            Description
          </span>
          <p className="font-medium font-new-sans text-[#44403C] text-sm leading-relaxed">
            {ticket.description}
          </p>
        </div>
      </div>

      {/* Attached files */}
      {ticket.attachedFiles.length > 0 && (
        <div className="flex flex-col gap-4 rounded-2xl border border-[#D6D3D1] bg-[#F5F3EF] p-6">
          <h2 className="font-extralight font-new-serif text-2xl text-[#44403C]">
            Attached Files
          </h2>
          <div className="flex flex-col gap-2">
            {ticket.attachedFiles.map((fileId) => (
              <div
                key={fileId}
                className="flex items-center gap-3 rounded-xl border border-[#D6D3D1] bg-white px-4 py-3"
              >
                <svg
                  width="15"
                  height="15"
                  viewBox="0 0 24 24"
                  fill="none"
                  aria-hidden="true"
                  className="shrink-0 text-[#A8A29E]"
                >
                  <path
                    d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48"
                    stroke="currentColor"
                    strokeWidth="1.5"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  />
                </svg>
                <span className="truncate font-new-sans text-[#44403C] text-sm">
                  {fileId.split("/").pop() ?? fileId}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Actions */}
      <div className="flex flex-wrap gap-3">
        <button
          type="button"
          onClick={handleDelete}
          disabled={deleteMutation.isPending || cancelMutation.isPending}
          className="inline-flex h-11 items-center gap-2 rounded-lg border border-[#B91C1C] px-5 font-medium font-new-sans text-[#B91C1C] text-sm transition-colors hover:bg-[#FEF2F2] disabled:cursor-not-allowed disabled:opacity-40"
        >
          <TrashIcon />
          {deleteMutation.isPending ? "Deleting..." : "Delete Ticket"}
        </button>

        <button
          type="button"
          onClick={handleArchive}
          disabled={ticket.status !== TicketStatus.Open || cancelMutation.isPending || deleteMutation.isPending}
          className="inline-flex h-11 items-center gap-2 rounded-lg border border-[#D6D3D1] px-5 font-medium font-new-sans text-[#44403C] text-sm transition-colors hover:bg-[#EDE9E3] disabled:cursor-not-allowed disabled:opacity-40"
        >
          <ArchiveIcon />
          Archive Ticket
        </button>
      </div>
    </div>
  );
}

function InfoRow({
  label,
  children,
}: {
  label: string;
  children: React.ReactNode;
}) {
  return (
    <div className="flex items-center justify-between border-[#E7E5E4] border-t py-4">
      <span className="font-new-sans text-[#A8A29E] text-sm">{label}</span>
      {children}
    </div>
  );
}

function TrashIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" aria-hidden="true">
      <path
        d="M3 6h18M8 6V4h8v2M19 6l-1 14H6L5 6"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function ArchiveIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" aria-hidden="true">
      <rect x="2" y="3" width="20" height="5" rx="1" stroke="currentColor" strokeWidth="1.5" />
      <path
        d="M4 8v11a1 1 0 001 1h14a1 1 0 001-1V8"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
      />
      <path d="M10 12h4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
    </svg>
  );
}

function SupportTicketDetailPage() {
  const params = useParams();
  const ticketId = params.id as string;

  return (
    <div className="mx-auto max-w-2xl">
      <Link
        href="/support"
        className="mb-8 inline-flex items-center gap-2 font-new-sans text-[#44403C] text-sm transition-opacity hover:opacity-70"
      >
        <svg width="16" height="16" viewBox="0 0 16 16" fill="none" aria-hidden="true">
          <path
            d="M10 3L5 8l5 5"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
        Back
      </Link>

      <SupportTicketDetail ticketId={ticketId} />
    </div>
  );
}

export default function Page() {
  return (
    <Suspense
      fallback={
        <div className="mx-auto max-w-2xl">
          <div className="flex flex-col gap-4 pt-16">
            {[1, 2, 3].map((i) => (
              <div key={i} className="h-10 animate-pulse rounded-lg bg-[#EDE9E3]" />
            ))}
          </div>
        </div>
      }
    >
      <SupportTicketDetailPage />
    </Suspense>
  );
}

