}

type SortKey = "date" | "category" | "related" | "subject" | "status";
type SortDir = "asc" | "desc";

interface ColumnDef {
  label: string;
  sortKey?: SortKey;
}

const COLUMNS: ColumnDef[] = [
  { label: "Ticket ID" },
  { label: "Date", sortKey: "date" },
  { label: "Issue Category", sortKey: "category" },
  { label: "Related", sortKey: "related" },
  { label: "Description", sortKey: "subject" },
  { label: "Status", sortKey: "status" },
  { label: "Actions" },
];

function sortTickets(
  tickets: TicketListItem[],
  key: SortKey,
  dir: SortDir,
): TicketListItem[] {
  return [...tickets].sort((aa, bb) => {
    let cmp = 0;
    if (key === "date") {
      cmp = new Date(aa.createdAt).getTime() - new Date(bb.createdAt).getTime();
    } else if (key === "category") {
      cmp = aa.category.localeCompare(bb.category);
    } else if (key === "related") {
      cmp = (aa.referenceId ?? "").localeCompare(bb.referenceId ?? "");
    } else if (key === "subject") {
      cmp = aa.subject.localeCompare(bb.subject);
    } else if (key === "status") {
      cmp = aa.status.localeCompare(bb.status);
    }
    return dir === "asc" ? cmp : -cmp;
  });
}

function SortIcon({ active, dir }: { active: boolean; dir: SortDir }) {
  return (
    <svg
      aria-hidden="true"
      className="shrink-0"
      fill="none"
      height="12"
      viewBox="0 0 12 12"
      width="12"
    >
      <path
        d="M6 1v10M3 4l3-3 3 3"
        stroke={active && dir === "asc" ? "#44403C" : "#D6D3D1"}
        strokeLinecap="round"
        strokeLinejoin="round"
        strokeWidth="1.2"
      />
      <path
        d="M3 8l3 3 3-3"
        stroke={active && dir === "desc" ? "#44403C" : "#D6D3D1"}
        strokeLinecap="round"
        strokeLinejoin="round"
        strokeWidth="1.2"
      />
    </svg>
  );
}

function TicketListContent({
  isLoading,
  isAuthenticated,
  tickets,
  onTicketClick,
}: {
  isLoading: boolean;
  isAuthenticated: boolean;
  tickets: TicketListItem[];
  onTicketClick: (id: string) => void;
}) {
  const [sortKey, setSortKey] = useState<SortKey>("date");
  const [sortDir, setSortDir] = useState<SortDir>("desc");

  function handleSort(key: SortKey) {
    if (sortKey === key) {
      setSortDir((prev) => (prev === "asc" ? "desc" : "asc"));
    } else {
      setSortKey(key);
      setSortDir("asc");
    }
  }

  if (isLoading) return <TicketSkeleton />;
  if (!isAuthenticated) return <GuestEmptyState />;
  if (tickets.length === 0) return <AuthEmptyState />;

  const sorted = sortTickets(tickets, sortKey, sortDir);

  return (
    <>
      <div className="sm:hidden">
        <MobileTicketList onTicketClick={onTicketClick} tickets={sorted} />
      </div>
      <div className="hidden w-full overflow-x-auto sm:block">
        <table className="w-full min-w-[700px]">
          <thead>
            <tr className="border-[#E7E5E4] border-b">
              {COLUMNS.map((col) => (
                <th
                  className="py-3 pr-3 pl-6 text-left first:pl-6 last:pr-4"
                  key={col.label}
                >
                  {col.sortKey ? (
                    <button
                      className="flex items-center gap-1 font-medium font-new-sans text-[#A8A29E] text-xs transition-colors hover:text-[#44403C]"
                      onClick={() => handleSort(col.sortKey as SortKey)}
                      type="button"
                    >
                      {col.label}
                      <SortIcon
                        active={sortKey === col.sortKey}
                        dir={sortDir}
                      />
                    </button>
                  ) : (
                    <span className="font-medium font-new-sans text-[#A8A29E] text-xs">
                      {col.label}
                    </span>
                  )}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {sorted.map((ticket) => (
              <TicketTableRow
                key={ticket.id}
                onClick={() => onTicketClick(ticket.id)}
                ticket={ticket}
              />
            ))}
          </tbody>
        </table>
      </div>
    </>
  );
}

function TicketSkeleton() {
  return (
    <div className="flex flex-col gap-3 p-6">
      {[1, 2, 3].map((i) => (
        <div className="h-16 animate-pulse rounded-xl bg-[#EDE9E3]" key={i} />
      ))}
    </div>
  );
}

function EmptyStateWrapper({ children }: { children: ReactNode }) {
  return (
    <div className="flex flex-col items-center justify-center gap-3 bg-[#EDE9E3] px-6 py-16 text-center">
      <svg
        aria-hidden="true"
        fill="none"
        height="28"
        viewBox="0 0 24 24"
        width="28"
      >
        <path
          d="M10 13a5 5 0 007.54.54l3-3a5 5 0 00-7.07-7.07l-1.72 1.71"
          stroke="#A8A29E"
          strokeLinecap="round"
          strokeLinejoin="round"
          strokeWidth="1.5"
        />
        <path
          d="M14 11a5 5 0 00-7.54-.54l-3 3a5 5 0 007.07 7.07l1.71-1.71"
          stroke="#A8A29E"
          strokeLinecap="round"
          strokeLinejoin="round"
          strokeWidth="1.5"
        />
      </svg>
      {children}
    </div>
  );
}

function GuestEmptyState() {
  return (
    <EmptyStateWrapper>
      <div className="flex flex-col gap-1">
        <p className="font-medium font-new-sans text-[#A8A29E]">
          Nothing to see here yet
        </p>
        <p className="font-new-sans text-sm">
          Login to see your created support tickets
        </p>
      </div>
    </EmptyStateWrapper>
  );
}

function AuthEmptyState() {
  return (
    <EmptyStateWrapper>
      <div className="flex flex-col gap-1">
        <p className="font-medium font-new-sans text-[#A8A29E]">
          We are up to date
        </p>
        <p className="font-new-sans text-[#A8A29E] text-sm">
          You don't have support tickets yet.
        </p>
      </div>
    </EmptyStateWrapper>
  );
}

function InfoRow({
  label,
  children,
}: {
  label: string;
  children: ReactNode;
}) {
  return (
    <div className="flex items-center justify-between border-[#E7E5E4] border-t py-4">
      <span className="font-new-sans text-[#A8A29E] text-sm">{label}</span>
      {children}
    </div>
  );
}

function TrashIcon() {
  return (
    <svg
      width="16"
      height="16"
      viewBox="0 0 24 24"
      fill="none"
      aria-hidden="true"
    >
      <path
        d="M3 6h18M8 6V4h8v2M19 6l-1 14H6L5 6"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function ArchiveIcon() {
  return (
    <svg
      width="16"
      height="16"
      viewBox="0 0 24 24"
